#!/usr/bin/env node
/**
 * generate-ctv-city-articles.mjs
 * Generates "CTV advertising for local businesses in [city], [state]" articles for 51 US cities.
 * Usage: node scripts/generate-ctv-city-articles.mjs [--dry-run]
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const CONTENT = path.join(__dirname, '../content/blog');
const DRY_RUN = process.argv.includes('--dry-run');
let written = 0, skipped = 0;

function emit(slug, content) {
  const out = path.join(CONTENT, `${slug}.mdx`);
  if (fs.existsSync(out)) { skipped++; return; }
  if (DRY_RUN) { console.log(`[dry] ${slug}`); written++; return; }
  fs.writeFileSync(out, content, 'utf8');
  console.log(`[ok]  ${slug}`);
  written++;
}

